// ---------------------------------------------------------------------------
// 8. item-groups.ts — item slug values in arrays -> Item constants
//    Keys of the outer Record stay as raw strings; only array element values change.
// ---------------------------------------------------------------------------
{
  const filePath = join(root, "app", "lib", "data", "item-groups.ts");
  let src = readFileSync(filePath, "utf-8");

  // Replace only array element values (strings inside [...])
  // Use replaceInArrayField approach — but the keys are arbitrary group names,
  // so we can't name them. Instead, use regex to match the array body patterns.
  // Strategy: parse line by line and replace quoted strings that appear as array elements.
  // A line that is an array element looks like: whitespace + "slug", or whitespace + "slug"
  // (indented by at least 2 spaces and not followed by : indicating an object key)
  const lines = src.split("\n");
  const newLines = lines.map((line) => {
    // Match lines that are array elements: leading whitespace, then a quoted string, optional comma
    // NOT object keys (which would have : after the closing quote)
    const arrayElemMatch = line.match(/^(\s+)"([^"]+)"(\s*,?\s*)$/);
    if (arrayElemMatch) {
      const [, indent, slug, trailing] = arrayElemMatch as [string, string, string, string];
      const ref = itemMap.get(slug);
      if (ref) {
        replacementCount++;
        return `${indent}${ref}${trailing}`;
      }
    }
    return line;
  });
  src = newLines.join("\n");

  src = ensureImport(src, `import { Item } from "./consts";`);

  writeFileSync(filePath, src, "utf-8");
  console.log(`Rewrote ${filePath}`);
}

console.log(`\nTotal replacements: ${replacementCount}`);
